from __future__ import annotations

INTERACTIVE_GAME_RUNTIME_CSS = """
:root{color-scheme:light;--bg:#f8fafc;--panel:#fff;--panel-soft:#f1f5f9;--ink:#0f172a;--muted:#475569;--line:#dbe4f0;--accent:#f43f5e;--accent-soft:rgba(244,63,94,.1);--good:#16a34a;--bad:#dc2626;--shadow:0 10px 30px rgba(15,23,42,.08)}*{box-sizing:border-box}body{margin:0;font-family:Inter,"PingFang SC","Microsoft YaHei",sans-serif;background:linear-gradient(180deg,#fff7f8 0%,var(--bg) 100%);color:var(--ink)}.app{min-height:100vh;padding:14px}.shell{margin:0 auto;max-width:1180px;background:rgba(255,255,255,.97);border:1px solid rgba(219,228,240,.9);border-radius:18px;box-shadow:var(--shadow);overflow:hidden}.hero{position:relative;padding:14px 18px 12px;border-bottom:1px solid var(--line);background:radial-gradient(circle at top right,rgba(244,63,94,.12),transparent 34%),linear-gradient(180deg,rgba(255,255,255,.99),rgba(248,250,252,.98))}.hero-copy{min-width:0;max-width:calc(100% - 260px)}.title{margin:0;font-size:18px;font-weight:700;line-height:1.3}.subtitle{margin:4px 0 0;color:var(--muted);font-size:12px;line-height:1.45}.meta{position:absolute;top:12px;right:14px;display:flex;flex-wrap:wrap;justify-content:flex-end;gap:6px;max-width:240px;z-index:2}.metric{display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(219,228,240,.96);background:rgba(255,255,255,.9);backdrop-filter:blur(10px);border-radius:999px;padding:5px 8px;white-space:nowrap;box-shadow:0 4px 14px rgba(15,23,42,.06)}.metric-label{font-size:10px;color:#64748b}.metric-value{font-size:12px;font-weight:700}.content{padding:14px 18px 18px}.instructions{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:12px}.instruction{background:var(--panel-soft);border:1px solid var(--line);border-radius:999px;padding:6px 10px;font-size:12px;color:var(--muted)}.feedback{min-height:40px;border-radius:12px;border:1px solid var(--line);background:var(--panel-soft);padding:10px 12px;font-size:13px;line-height:1.5}.feedback.good{border-color:rgba(22,163,74,.22);background:rgba(22,163,74,.08);color:var(--good)}.feedback.bad{border-color:rgba(220,38,38,.22);background:rgba(220,38,38,.08);color:var(--bad)}.workspace{margin-top:14px;display:grid;gap:14px}.card{border:1px solid var(--line);background:var(--panel);border-radius:14px;padding:14px}.card-title{margin:0 0 10px;font-size:14px;font-weight:700}.chip-list,.zone-list,.node-list,.sort-list{display:grid;gap:12px}.chip{display:inline-flex;align-items:center;gap:8px;padding:10px 12px;border-radius:12px;border:1px solid var(--line);background:#fff;box-shadow:0 2px 8px rgba(15,23,42,.03);cursor:grab;user-select:none}.chip small{color:var(--muted)}.zones{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.zone{min-height:140px;border:2px dashed var(--line);border-radius:14px;padding:12px;background:linear-gradient(180deg,rgba(248,250,252,.85),#fff)}.zone.over{border-color:var(--accent);background:var(--accent-soft)}.zone-title{font-size:13px;font-weight:700}.slot-list{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px}.slot-chip{padding:8px 10px;border-radius:999px;background:rgba(244,63,94,.08);color:var(--ink);border:1px solid rgba(244,63,94,.15);font-size:12px}.sort-item{display:grid;grid-template-columns:auto 1fr auto;align-items:center;gap:12px;padding:12px;border-radius:12px;border:1px solid var(--line);background:#fff}.sort-index{width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;border-radius:999px;background:var(--accent-soft);color:var(--accent);font-size:12px;font-weight:700}.sort-actions,.toolbar{display:flex;flex-wrap:wrap;gap:8px}.toolbar{justify-content:flex-end}button{appearance:none;border:1px solid var(--line);background:#fff;color:var(--ink);border-radius:10px;padding:9px 12px;font-size:13px;font-weight:600;cursor:pointer}button.primary{background:var(--accent);border-color:var(--accent);color:#fff}button.ghost.active{border-color:var(--accent);background:var(--accent-soft);color:var(--accent)}.link-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.node{width:100%;text-align:left}.node.active{border-color:var(--accent);background:var(--accent-soft);color:var(--accent)}.pair-list{display:grid;gap:8px;margin-top:12px}.pair{display:flex;justify-content:space-between;align-items:center;gap:12px;padding:10px 12px;border:1px solid var(--line);border-radius:12px;background:#fff;font-size:13px}@media (max-width:860px){.hero-copy{max-width:none;padding-right:0}.meta{position:static;justify-content:flex-start;max-width:none;margin-top:10px}.link-grid{grid-template-columns:1fr}}
""".strip()

INTERACTIVE_GAME_RUNTIME_SCRIPT = """
(function(){const g=window.__SPECTRA_INTERACTIVE_GAME__,w=document.getElementById("workspace"),f=document.getElementById("feedback"),s=document.getElementById("score"),p=document.getElementById("progress"),t=document.getElementById("timer"),c=document.getElementById("check-btn"),r=document.getElementById("reset-btn"),st={subtype:g.subtype,score:0,completed:false,remainingSeconds:Number(g.score_policy&&g.score_policy.timer_seconds)||null,timerId:null,placements:{},order:[],selectedLeftId:null,links:{}};document.getElementById("title").textContent=g.title||"互动游戏";document.getElementById("subtitle").textContent=g.subtitle||g.teaching_goal||"课堂操作型小游戏";document.getElementById("subtype").textContent=g.subtype==="drag_classification"?"拖拽归类":g.subtype==="sequence_sort"?"流程排序":g.subtype==="relationship_link"?"关系连线":"互动游戏";(Array.isArray(g.instructions)?g.instructions:[]).forEach(i=>{const e=document.createElement("div");e.className="instruction";e.textContent=i;document.getElementById("instructions").appendChild(e)});function msg(text,tone){f.textContent=text||"继续作答。";f.className="feedback"+(tone?" "+tone:"")}function stat(){const total=st.subtype==="drag_classification"?Object.keys(g.spec.correct_mapping||{}).length:st.subtype==="sequence_sort"?(g.spec.correct_order||[]).length:st.subtype==="relationship_link"?(g.spec.correct_links||[]).length:0;const done=st.subtype==="drag_classification"?Object.keys(st.placements).length:st.subtype==="sequence_sort"?(st.order||[]).length:Object.keys(st.links).length;s.textContent=String(st.score);p.textContent=total?done+"/"+total:"-";t.textContent=st.remainingSeconds===null?"不限时":st.remainingSeconds<=0?"00:00":String(Math.floor(st.remainingSeconds/60)).padStart(2,"0")+":"+String(st.remainingSeconds%60).padStart(2,"0")}function finish(correct,total,ok,no){const rule=g.completion_rule||{},threshold=typeof rule.pass_threshold==="number"?rule.pass_threshold:1,ratio=total?correct/total:0,success=ratio>=threshold;st.completed=success;st.score=success?Number(g.score_policy&&g.score_policy.max_score||100):Math.max(0,Math.round(Number(g.score_policy&&g.score_policy.max_score||100)*ratio));if(success&&st.timerId){window.clearInterval(st.timerId);st.timerId=null}stat();msg(success?(ok||rule.success_copy||"完成得很漂亮。"):(no||rule.failure_copy||"再试一次，你快接近正确答案了。"),success?"good":"bad")}function timer(){if(st.remainingSeconds===null||st.timerId)return;st.timerId=window.setInterval(()=>{if(st.remainingSeconds===null)return;st.remainingSeconds=Math.max(0,st.remainingSeconds-1);stat();if(st.remainingSeconds===0){window.clearInterval(st.timerId);st.timerId=null;msg("时间到，可以重开一轮再试。","bad")}},1000)}function dragPaint(){w.querySelectorAll(".zone").forEach(z=>{const id=z.dataset.zoneId,slots=z.querySelector(".slot-list");slots.innerHTML="";Object.keys(st.placements).forEach(itemId=>{if(st.placements[itemId]!==id)return;const item=(g.spec.items||[]).find(e=>e.id===itemId);if(!item)return;const chip=document.createElement("div");chip.className="slot-chip";chip.textContent=item.label;slots.appendChild(chip)})})}function dragRender(){const spec=g.spec||{},pool=document.createElement("div");pool.className="card";pool.innerHTML='<h2 class="card-title">待归类项目</h2><div class="chip-list" id="drag-pool"></div>';(spec.items||[]).forEach(item=>{const chip=document.createElement("div");chip.className="chip";chip.draggable=true;chip.dataset.itemId=item.id;chip.innerHTML="<strong>"+item.label+"</strong>"+(item.hint?"<small>"+item.hint+"</small>":"");chip.addEventListener("dragstart",e=>{timer();e.dataTransfer.setData("text/plain",item.id)});pool.querySelector("#drag-pool").appendChild(chip)});const zones=document.createElement("div");zones.className="card";zones.innerHTML='<h2 class="card-title">归类区域</h2><div class="zones" id="zones"></div>';(spec.zones||[]).forEach(zone=>{const el=document.createElement("div");el.className="zone";el.dataset.zoneId=zone.id;el.innerHTML='<div class="zone-title">'+zone.label+'</div><div class="slot-list"></div>';el.addEventListener("dragover",e=>{e.preventDefault();el.classList.add("over")});el.addEventListener("dragleave",()=>el.classList.remove("over"));el.addEventListener("drop",e=>{e.preventDefault();el.classList.remove("over");const itemId=e.dataTransfer.getData("text/plain");if(!itemId)return;st.placements[itemId]=zone.id;dragPaint();stat()});zones.querySelector("#zones").appendChild(el)});w.appendChild(pool);w.appendChild(zones)}function dragCheck(){const m=g.spec.correct_mapping||{},total=Object.keys(m).length;let correct=0;Object.keys(m).forEach(id=>{if(st.placements[id]===m[id])correct+=1});finish(correct,total,g.spec.feedback_copy&&g.spec.feedback_copy.correct||"归类正确。",g.spec.feedback_copy&&g.spec.feedback_copy.incorrect||"还有项目放错区域。")}function sortPaint(){const list=w.querySelector("#sort-list");if(!list)return;list.innerHTML="";st.order.forEach((id,index)=>{const item=(g.spec.items||[]).find(e=>e.id===id);if(!item)return;const row=document.createElement("div");row.className="sort-item";row.innerHTML='<div class="sort-index">'+(index+1)+'</div><div><strong>'+item.label+'</strong>'+(item.hint?'<div style="font-size:12px;color:var(--muted);margin-top:4px">'+item.hint+"</div>":"")+'</div><div class="sort-actions"><button type="button">上移</button><button type="button">下移</button></div>';const btns=row.querySelectorAll("button");btns[0].addEventListener("click",()=>{timer();if(index===0)return;const next=st.order.slice(),tmp=next[index-1];next[index-1]=next[index];next[index]=tmp;st.order=next;sortPaint();stat()});btns[1].addEventListener("click",()=>{timer();if(index===st.order.length-1)return;const next=st.order.slice(),tmp=next[index+1];next[index+1]=next[index];next[index]=tmp;st.order=next;sortPaint();stat()});list.appendChild(row)})}function sortRender(){st.order=(g.spec.items||[]).map(item=>item.id);const card=document.createElement("div");card.className="card";card.innerHTML='<h2 class="card-title">调整流程顺序</h2><div class="sort-list" id="sort-list"></div>';w.appendChild(card);sortPaint()}function sortCheck(){const order=g.spec.correct_order||[],total=order.length;let correct=0;order.forEach((id,index)=>{if(st.order[index]===id)correct+=1});finish(correct,total,g.spec.completion_copy||"流程顺序正确。","顺序还可以再调整一下。")}function linkPaint(){w.querySelectorAll("#left-list .node").forEach(btn=>btn.classList.toggle("active",btn.dataset.nodeId===st.selectedLeftId));const list=w.querySelector("#pair-list");if(!list)return;list.innerHTML="";Object.keys(st.links).forEach(leftId=>{const left=(g.spec.left_nodes||[]).find(i=>i.id===leftId),right=(g.spec.right_nodes||[]).find(i=>i.id===st.links[leftId]);if(!left||!right)return;const pair=document.createElement("div");pair.className="pair";pair.innerHTML="<span>"+left.label+"</span><strong>"+right.label+"</strong>";list.appendChild(pair)})}function linkRender(){const spec=g.spec||{},card=document.createElement("div");card.className="card";card.innerHTML='<h2 class="card-title">建立关系连线</h2><div class="link-grid"><div><div style="font-size:12px;color:var(--muted);margin-bottom:8px">左侧概念</div><div class="node-list" id="left-list"></div></div><div><div style="font-size:12px;color:var(--muted);margin-bottom:8px">右侧目标</div><div class="node-list" id="right-list"></div></div></div><div class="pair-list" id="pair-list"></div>';(spec.left_nodes||[]).forEach(node=>{const btn=document.createElement("button");btn.type="button";btn.className="node ghost";btn.textContent=node.label;btn.dataset.nodeId=node.id;btn.addEventListener("click",()=>{timer();st.selectedLeftId=node.id;linkPaint()});card.querySelector("#left-list").appendChild(btn)});(spec.right_nodes||[]).forEach(node=>{const btn=document.createElement("button");btn.type="button";btn.className="node";btn.textContent=node.label;btn.dataset.nodeId=node.id;btn.addEventListener("click",()=>{if(!st.selectedLeftId){msg("先选中左侧概念，再点右侧目标建立连线。");return}st.links[st.selectedLeftId]=node.id;st.selectedLeftId=null;linkPaint();stat()});card.querySelector("#right-list").appendChild(btn)});w.appendChild(card);linkPaint()}function linkCheck(){const links=Array.isArray(g.spec.correct_links)?g.spec.correct_links:[],total=links.length;let correct=0;links.forEach(pair=>{if(st.links[pair.left_id]===pair.right_id)correct+=1});finish(correct,total,g.spec.feedback_copy&&g.spec.feedback_copy.correct||"关系连线全部正确。",g.spec.feedback_copy&&g.spec.feedback_copy.incorrect||"还有关系可以再校对一下。")}if(g.subtype==="drag_classification")dragRender();else if(g.subtype==="sequence_sort")sortRender();else linkRender();stat();c.addEventListener("click",()=>{if(g.subtype==="drag_classification")dragCheck();else if(g.subtype==="sequence_sort")sortCheck();else linkCheck()});r.addEventListener("click",()=>window.location.reload())})();
""".strip()
